<?php

namespace Worldpay\Api\Builders\PaymentProcessing;

use Worldpay\Api\ApiResponse;
use Worldpay\Api\Entities\Customer;
use Worldpay\Api\Entities\Order;
use Worldpay\Api\Enums\Api;
use Worldpay\Api\Enums\RiskFactors;
use Worldpay\Api\Exceptions\ApiClientException;
use Worldpay\Api\Providers\AccessWorldpayConfigProvider;
use Worldpay\Api\Services\PaymentProcessingServiceInterface;
use Worldpay\Api\Services\Validators\BaseValidator;
use Worldpay\Api\Services\Validators\PaymentProcessingValidator;
use Worldpay\Api\Services\Validators\PaymentProcessingValidators\HPPApiValidator;
use Worldpay\Api\Services\Validators\PaymentProcessingValidators\PaymentsApiValidator;
use Worldpay\Api\ValueObjects\BillingAddress;
use Worldpay\Api\ValueObjects\PaymentInstrument;
use Worldpay\Api\ValueObjects\ResultURLs;
use Worldpay\Api\ValueObjects\ShippingAddress;
use Worldpay\Api\ValueObjects\ThreeDS;

class PaymentProcessingBuilder
{
	/**
	 * @var string A unique reference generated by you that is used to identify a payment throughout its lifecycle.
	 */
	public string $transactionReference;

	/**
	 * @var int The payment amount. This is a whole number with an exponent.
	 */
	public int $amount;

	/**
	 * @var string The 3 character ISO currency code.
	 */
	public string $currency = 'GBP';

	/**
	 * @var BillingAddress An object containing the billingAddress information.
	 */
	public BillingAddress $billingAddress;

	/**
	 * @var ShippingAddress An object containing the shippingAddress information.
	 */
	public ShippingAddress $shippingAddress;

	/**
	 * @var Customer An object containing the customer information.
	 */
	public Customer $customer;

	/**
	 * @var string A text displayed to your customer on payment pages.
	 */
	public string $description;

	/**
	 * @var ResultURLs An object containing the different URLs to redirect customers to when the payment result is received.
	 */
	public ResultURLs $resultURLs;

	/**
	 * @var int Allows you to configure the duration your customer can access the payment link.
	 */
	public int $expiry;

	/**
	 * @var string The email address used for an electronic delivery.
	 */
	public string $shippingEmail;

	/**
	 * @var string The shipping method used for delivery.
	 */
	public string $shippingMethod;

	/**
	 * @var PaymentInstrument
	 */
	public PaymentInstrument $paymentInstrument;

	/**
	 * @var string
	 */
	public string $paymentMethod;

	/**
	 * @var ThreeDS
	 */
	public ThreeDS $threeDS;

	/**
	 * @var bool
	 */
	public bool $autoSettlement;

	/**
	 * @var string
	 */
	public string $fraudType;

	/**
	 * @var bool Creates a token for the payment details supplied.
	 */
	public bool $tokenCreation = false;

	/**
	 * @var string The type of token to be created.
	 */
	public string $tokenType = 'worldpay';

	/**
	 * @var string A namespace is used to group up to 16 cards, e.g. for one customer.
	 */
	public string $tokenNamespace;

	/**
	 * @var string A description of your token. If not supplied, a default description is created for you.
	 */
	public string $tokenDescription;

	/**
	 * @var string Option to choose how the customer could opt into their payment details being tokenized (HPP).
	 */
	public string $tokenOption;

	/**
	 * @var string Enum. See CustomerAgreementType.
	 */
	public string $customerAgreementType;

	/**
	 * @var string Enum. See StoredCardUsage.
	 */
	public string $storedCardUsage;

	/**
	 * @var string Unique reference provided by card schemes.
	 */
	public string $schemeReference;

	/**
	 * @var string By default, a payment will be sentForCancellation if the address or postcode AVS is notMatched.
	 *             Set disabled to continue with sentForSettlement.
	 */
	public string $cancelOnAVSNotMatched;

	/**
	 * @var string By default, a payment will be sentForCancellation if the CVC is notMatched.
	 *             Set disabled to continue with sentForSettlement.
	 */
	public string $cancelOnCVCNotMatched;

	/**
	 * @return ApiResponse
	 * @throws ApiClientException
	 */
	public function execute(): ApiResponse {
		$configProvider = AccessWorldpayConfigProvider::instance();
		$apiService = $configProvider->getApiService();
		if (! class_exists($apiService) || ! ((new $apiService()) instanceof PaymentProcessingServiceInterface)) {
			throw new ApiClientException($configProvider->getApi() . ' does not support payment processing.');
		}

		return $apiService::submitPayment($this);
	}

	/**
	 * @param  string  $transactionReference
	 * @return PaymentProcessingBuilder
	 */
	public function withTransactionReference(string $transactionReference): PaymentProcessingBuilder {
		$this->transactionReference = $transactionReference;

		return $this;
	}

	/**
	 * @param  int  $amount
	 * @return PaymentProcessingBuilder
	 */
	public function withAmount(int $amount): PaymentProcessingBuilder {
		$this->amount = $amount;

		return $this;
	}

	/**
	 * @param  string  $currency
	 * @return PaymentProcessingBuilder
	 */
	public function withCurrency(string $currency): PaymentProcessingBuilder {
		$this->currency = $currency;

		return $this;
	}

	/**
	 * @param  BillingAddress  $billingAddress
	 * @return PaymentProcessingBuilder
	 */
	public function withBillingAddress(BillingAddress $billingAddress): PaymentProcessingBuilder {
		$this->billingAddress = $billingAddress;

		return $this;
	}

	/**
	 * @param  ShippingAddress  $shippingAddress
	 * @return PaymentProcessingBuilder
	 */
	public function withShippingAddress(ShippingAddress $shippingAddress): PaymentProcessingBuilder {
		$this->shippingAddress = $shippingAddress;

		return $this;
	}

	/**
	 * @param  Customer  $customer
	 * @return PaymentProcessingBuilder
	 */
	public function withCustomer(Customer $customer): PaymentProcessingBuilder {
		$this->customer = $customer;

		return $this;
	}

	/**
	 * @param  string  $description
	 * @return PaymentProcessingBuilder
	 */
	public function withDescription(string $description): PaymentProcessingBuilder {
		$this->description = $description;

		return $this;
	}

	/**
	 * @param  ResultURLs  $resultURLs
	 * @return PaymentProcessingBuilder
	 */
	public function withResultURLs(ResultURLs $resultURLs): PaymentProcessingBuilder {
		$this->resultURLs = $resultURLs;

		return $this;
	}

	/**
	 * @param  int  $expiry
	 * @return PaymentProcessingBuilder
	 */
	public function withExpiry(int $expiry): PaymentProcessingBuilder {
		$this->expiry = $expiry;

		return $this;
	}

	/**
	 * @param  string  $email
	 * @return PaymentProcessingBuilder
	 */
	public function withShippingEmail(string $email): PaymentProcessingBuilder {
		$this->shippingEmail = $email;

		return $this;
	}

	/**
	 * @param  string  $method
	 * @return PaymentProcessingBuilder
	 */
	public function withShippingMethod(string $method): PaymentProcessingBuilder {
		$this->shippingMethod = $method;

		return $this;
	}

	/**
	 * @param  PaymentInstrument  $paymentInstrument
	 * @return PaymentProcessingBuilder
	 */
	public function withPaymentInstrument(PaymentInstrument $paymentInstrument): PaymentProcessingBuilder {
		$this->paymentInstrument = $paymentInstrument;

		return $this;
	}

	/**
	 * @param  string  $paymentMethod  (see PaymentMethod Enum)
	 *
	 * @return PaymentProcessingBuilder
	 */
	public function withPaymentMethod(string $paymentMethod): PaymentProcessingBuilder {
		$this->paymentMethod = $paymentMethod;

		return $this;
	}

	/**
	 * @param  ThreeDS  $threeDS
	 * @return PaymentProcessingBuilder
	 */
	public function withThreeDS(ThreeDS $threeDS): PaymentProcessingBuilder {
		$this->threeDS = $threeDS;

		return $this;
	}

	/**
	 * @param  bool  $status
	 *
	 * @return $this
	 */
	public function withAutoSettlement(bool $status=true): PaymentProcessingBuilder {
		$this->autoSettlement = $status;

		return $this;
	}

	/**
	 * @param  string  $fraudType  (see FraudType Enum)
	 *
	 * @return $this
	 */
	public function withFraudType(string $fraudType): PaymentProcessingBuilder {
		$this->fraudType = $fraudType;

		return $this;
	}

	/**
	 * @return $this
	 */
	public function withTokenCreation(): PaymentProcessingBuilder {
		$this->tokenCreation = true;

		return $this;
	}

	/**
	 * @param  string  $namespace
	 *
	 * @return $this
	 */
	public function withTokenNamespace(string $namespace): PaymentProcessingBuilder {
		$this->tokenNamespace = $namespace;

		return $this;
	}

	/**
	 * @param  string  $description
	 *
	 * @return $this
	 */
	public function withTokenDescription(string $description): PaymentProcessingBuilder {
		$this->tokenDescription = $description;

		return $this;
	}

	/**
	 * @param  string  $option (see TokenOption Enum)
	 *
	 * @return $this
	 */
	public function withTokenOption(string $option): PaymentProcessingBuilder {
		$this->tokenOption = $option;

		return $this;
	}

	/**
	 * @param  Order  $order
	 *
	 * @return PaymentProcessingBuilder
	 */
	public function withOptionalOrder(Order $order): PaymentProcessingBuilder {
		if (isset($this->transactionReference) && !empty($order->id)) {
			$this->withTransactionReference($this->transactionReference . '_' . $order->id);
		}
		if (!empty($order->amount)) {
			$this->withAmount($order->amount);
		}
		if (!empty($order->currency)) {
			$this->withCurrency($order->currency);
		}
		$validatorType = '';
		switch ( AccessWorldpayConfigProvider::instance()->getApi()) {
			case Api::ACCESS_WORLDPAY_HPP_API:
				$validatorType = HPPApiValidator::class;
				break;
			case Api::ACCESS_WORLDPAY_PAYMENTS_API:
				$validatorType = PaymentsApiValidator::class;
				break;
		}

		if (isset($order->customer)) {
			if (!empty($order->customer->phoneNumber)) {
				$sanitizedPhoneNumber = PaymentProcessingValidator::sanitizeCustomerPhoneNumber($order->customer->phoneNumber);
				if (BaseValidator::hasValidLength(
					$sanitizedPhoneNumber,
					$validatorType::CUSTOMER_PHONE_NUMBER_MIN_SIZE,
					$validatorType::CUSTOMER_PHONE_NUMBER_MAX_SIZE)) {
					$order->customer->phoneNumber = PaymentProcessingValidator::sanitizeCustomerPhoneNumber($order->customer->phoneNumber);
				} else {
					$order->customer->phoneNumber = '';
				}
			}
			if (isset($order->customer->firstName) && ! BaseValidator::hasValidLength(
					$order->customer->firstName,
					$validatorType::CUSTOMER_FIRST_NAME_MIN_SIZE,
					$validatorType::CUSTOMER_FIRST_NAME_MAX_SIZE
				)) {
				$order->customer->firstName = '';
			}
			if (isset($order->customer->lastName) && ! BaseValidator::hasValidLength(
					$order->customer->lastName,
					$validatorType::CUSTOMER_LAST_NAME_MIN_SIZE,
					$validatorType::CUSTOMER_LAST_NAME_MAX_SIZE
				)) {
				$order->customer->lastName = '';
			}
			if (isset($order->customer->email) && ! BaseValidator::hasValidLength(
					$order->customer->email,
					$validatorType::CUSTOMER_EMAIL_MIN_SIZE,
					$validatorType::CUSTOMER_EMAIL_MAX_SIZE
				)) {
				$order->customer->email = '';
			}

			$this->withCustomer($order->customer);
		}
		if (isset($order->billingAddress)) {
			$newBillingAddress = new BillingAddress();
			if (PaymentProcessingValidator::hasBillingAddressRequiredFields($validatorType, $order->billingAddress)) {
				$newBillingAddress->address1 = $order->billingAddress->address1;
				$newBillingAddress->postalCode = $order->billingAddress->postalCode;
				$newBillingAddress->city = $order->billingAddress->city;
				$newBillingAddress->countryCode = $order->billingAddress->countryCode;

				if (isset($order->billingAddress->address2) && BaseValidator::hasValidLength(
						$order->billingAddress->address2,
						$validatorType::BILLING_ADDRESS2_MIN_SIZE,
						$validatorType::BILLING_ADDRESS2_MAX_SIZE
					)) {
					$newBillingAddress->address2 = $order->billingAddress->address2;
				}
				if (isset($order->billingAddress->address3) && BaseValidator::hasValidLength(
						$order->billingAddress->address3,
						$validatorType::BILLING_ADDRESS3_MIN_SIZE,
						$validatorType::BILLING_ADDRESS3_MAX_SIZE
					)) {
					$newBillingAddress->address3 = $order->billingAddress->address3;
				}
				if (isset($order->billingAddress->state) && BaseValidator::hasValidLength(
						$order->billingAddress->state,
						$validatorType::BILLING_STATE_MIN_SIZE,
						$validatorType::BILLING_STATE_MAX_SIZE
					)) {
					$newBillingAddress->state = $order->billingAddress->state;
				}

				$this->withBillingAddress($newBillingAddress);
			}
		}
		if (isset($order->shippingAddress)) {
			$newShippingAddress = new ShippingAddress();
			if (PaymentProcessingValidator::hasShippingAddressRequiredFields($validatorType, $order->shippingAddress)) {
				$newShippingAddress->address1 = $order->shippingAddress->address1;
				$newShippingAddress->postalCode = $order->shippingAddress->postalCode;
				$newShippingAddress->city = $order->shippingAddress->city;
				$newShippingAddress->countryCode = $order->shippingAddress->countryCode;

				if (isset($order->shippingAddress->address2) && BaseValidator::hasValidLength(
						$order->shippingAddress->address2,
						$validatorType::SHIPPING_ADDRESS2_MIN_SIZE,
						$validatorType::SHIPPING_ADDRESS2_MAX_SIZE
					)) {
					$newShippingAddress->address2 = $order->shippingAddress->address2;
				}
				if (isset($order->shippingAddress->address3) && BaseValidator::hasValidLength(
						$order->shippingAddress->address3,
						$validatorType::SHIPPING_ADDRESS3_MIN_SIZE,
						$validatorType::SHIPPING_ADDRESS3_MAX_SIZE
					)) {
					$newShippingAddress->address3 = $order->shippingAddress->address3;
				}
				if (isset($order->shippingAddress->state) && BaseValidator::hasValidLength(
						$order->shippingAddress->state,
						$validatorType::SHIPPING_STATE_MIN_SIZE,
						$validatorType::SHIPPING_STATE_MAX_SIZE
					)) {
					$newShippingAddress->state = $order->shippingAddress->state;
				}

				$this->withShippingAddress($newShippingAddress);
			}
		}

		return $this;
	}

	/**
	 * @param  string  $type
	 * @param  string  $usage
	 *
	 * @return $this
	 */
	public function withCustomerAgreement(string $type, string $usage): PaymentProcessingBuilder {
		$this->customerAgreementType = $type;
		$this->storedCardUsage = $usage;

		return $this;
	}

	/**
	 * @param  string  $schemeReference
	 *
	 * @return $this
	 */
	public function withSchemeReference(string $schemeReference): PaymentProcessingBuilder {
		$this->schemeReference = $schemeReference;

		return $this;
	}

	/**
	 * @param  string  $riskFactor (see RiskFactors Enum)
	 * @param  string  $status (see Status Enum)
	 *
	 * @return $this
	 */
	public function withSettlementCancellationOn(string $riskFactor, string $status): PaymentProcessingBuilder {
		switch($riskFactor) {
			case RiskFactors::AVS_NOT_MATCHED:
				$this->cancelOnAVSNotMatched = $status;
				break;
			case RiskFactors::CVC_NOT_MATCHED:
				$this->cancelOnCVCNotMatched = $status;
				break;
		}

		return $this;
	}
}
